#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M_INT 2147483647
#define A_INT 1103515245
#define C_INT 12345

static inline double roundDoubleDev(double value) {
    int newValue = (int)(value);
    if (value - (double)newValue < 0.5)
        return (double)newValue;
    else
        return (double)newValue;
}

static inline double randuDev(__global int *seed, int index) {
    int num = A_INT * seed[index] + C_INT;
    seed[index] = num % M_INT;
    return fabs(((double)seed[index]) / ((double)M_INT));
}

static inline double randnDev(__global int *seed, int index) {
    double u = randuDev(seed, index);
    double v = randuDev(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

static inline int findIndexDev(__global const double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) return lengthCDF - 1;
    return index;
}

__kernel void likelihood_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *xj,
                                __global double *yj,
                                __global double *CDF,
                                __global int *ind,
                                __global int *objxy,
                                __global double *likelihood,
                                __global unsigned char *I,
                                __global double *u,
                                __global double *weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int *seed,
                                __global double *partial_sums,
                                __local double *buffer) {
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    arrayX[x] = xj[x] + 1.0 + 5.0 * randnDev(seed, x);
    arrayY[x] = yj[x] + -2.0 + 2.0 * randnDev(seed, x);

    double like = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDoubleDev(arrayX[x]) + objxy[y * 2 + 1];
        int indY = (int)roundDoubleDev(arrayY[x]) + objxy[y * 2];
        int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (idx >= max_size) idx = 0;
        ind[x * countOnes + y] = idx;

        double v1 = (double)I[idx] - 100.0;
        double v2 = (double)I[idx] - 228.0;
        like += (v1 * v1 - v2 * v2) / 50.0;
    }

    like = like / (double)countOnes;
    likelihood[x] = like;
    weights[x] = weights[x] * exp(like);
    partial_sums[x] = weights[x];
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = get_global_id(0);
    if (gid != 0) return;

    double sum = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        sum += partial_sums[i];
    }
    partial_sums[0] = sum;
}

__kernel void normalize_weights_kernel(__global double *weights,
                                       int Nparticles,
                                       __global double *partial_sums,
                                       __global double *CDF,
                                       __global double *u,
                                       __global int *seed) {
    int gid = get_global_id(0);
    if (gid != 0) return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0) sumWeights = 1.0;

    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) {
            CDF[i] = weights[i] + CDF[i - 1];
        }

        double u1 = (1.0 / (double)Nparticles) * randuDev(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + ((double)i / (double)Nparticles);
        }
    }
}

__kernel void find_index_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    int i = findIndexDev(CDF, Nparticles, u[j]);
    if (i == -1) i = Nparticles - 1;

    double newX = arrayX[i];
    double newY = arrayY[i];

    xj[j] = newX;
    yj[j] = newY;
    arrayX[j] = newX;
    arrayY[j] = newY;
    weights[j] = 1.0 / (double)Nparticles;
}

